args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?treatment ?treatmentLabel ?sideEffect ?sideEffectLabel
WHERE {
  wd:Q11081 wdt:P2176 ?treatment.
  ?treatment wdt:P1909 ?sideEffect.
  OPTIONAL { ?treatment rdfs:label ?treatmentLabel FILTER (LANG(?treatmentLabel) = "en") }
  OPTIONAL { ?sideEffect rdfs:label ?sideEffectLabel FILTER (LANG(?sideEffectLabel) = "en") }
}
